# policy_engine.py
from dataclasses import dataclass

@dataclass
class TaskSpec:
    task_type: str
    resource_path: str
    user_id: str
    agent_id: str

# In production, load from OPA or Cedar rather than hardcoding.
TASK_PERMISSION_POLICIES: dict[str, dict] = {
    "summarize": {
        "base_scopes": ["files:read:path:{resource_path}"],
        "max_duration_seconds": 300,
    },
    "draft_email": {
        "base_scopes": [
            "email:draft:to:{user_id}",  # draft only, not send
            "files:read:path:{resource_path}",
        ],
        "max_duration_seconds": 600,
    },
    "run_code": {
        "base_scopes": [
            "sandbox:exec:session:{task_id}",
            "files:read:path:{resource_path}",
            "files:write:path:/tmp/{task_id}",
        ],
        "max_duration_seconds": 900,
    },
}

class PolicyEngine:
    def compute_grant(self, task: TaskSpec, task_id: str) -> dict | None:
        """Returns scope grant, or None if task_type is unknown (deny)."""
        policy = TASK_PERMISSION_POLICIES.get(task.task_type)
        if policy is None:
            return None
        scopes = [
            s.format(resource_path=task.resource_path, user_id=task.user_id, task_id=task_id)
            for s in policy["base_scopes"]
        ]
        return {"scopes": scopes, "duration_seconds": policy["max_duration_seconds"]}

engine = PolicyEngine()
grant = engine.compute_grant(
    TaskSpec("summarize", "/docs/q3-report.pdf", "user-42", "summarizer-v2"),
    task_id="task-9001",
)
print(grant)
# {'scopes': ['files:read:path:/docs/q3-report.pdf'], 'duration_seconds': 300}

# Real-world: credit scoring tool with per-applicant scope enforcement
import jwt, time

SECRET = "prod-hmac-key"  # use RS256 in production

class CreditScoringTool:
    def query(self, applicant_id: str, token: str) -> dict:
        try:
            payload = jwt.decode(token, SECRET, algorithms=["HS256"])
        except jwt.InvalidTokenError as e:
            raise PermissionError(f"Invalid token: {e}")

        required = f"credit:query:applicant:{applicant_id}"
        granted = set(payload.get("scope", "").split())
        if required not in granted:
            print(f"[AUDIT] DENIED credit query applicant={applicant_id} task={payload.get('jti')}")
            raise PermissionError(f"Scope '{required}' not granted.")

        print(f"[AUDIT] GRANTED credit query applicant={applicant_id} task={payload.get('jti')}")
        return {"applicant_id": applicant_id, "score": 742, "risk": "low"}

tool = CreditScoringTool()
token = jwt.encode(
    {
        "sub": "loan-agent",
        "jti": "task-5521",
        "exp": int(time.time()) + 1200,
        "scope": "credit:query:applicant:applicant-001 files:read:path:/loans/loan-5521/*",
    },
    SECRET, algorithm="HS256",
)

result = tool.query("applicant-001", token)  # allowed
print("Result:", result)

try:
    tool.query("applicant-002", token)  # blocked -- prompt injection attempt
except PermissionError as e:
    print("Blocked:", e)
